import{_ as a,o as i,c as s,a2 as r}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Сервисы","description":"","frontmatter":{},"headers":[],"relativePath":"ru/api/services.md","filePath":"ru/api/services.md"}'),c={name:"ru/api/services.md"};function t(l,e,n,d,o,h){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="сервисы" tabindex="-1">Сервисы <a class="header-anchor" href="#сервисы" aria-label="Permalink to &quot;Сервисы&quot;">​</a></h1><p>Все сервисы Clearance находятся в <code>src/Services/</code> и разрешаются из контейнера, напр. <code>app(ContextService::class)</code>. Это слой, к которому стоит обращаться из контроллеров, политик и заданий (jobs) - везде, где модель <code>User</code> может не использовать трейт <code>HasClearance</code>.</p><h2 id="contextservice" tabindex="-1"><code>ContextService</code> <a class="header-anchor" href="#contextservice" aria-label="Permalink to &quot;`ContextService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\ContextService</code> (<code>src/Services/ContextService.php</code>) - это движок, стоящий за контекстной авторизацией. И <a href="/clearance-docs/ru/api/facade.html">фасад <code>Clearance</code></a>, и трейт <code>HasClearance</code> делегируют ему.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\ContextService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ContextService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">canIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasPermissionIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// alias</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasRoleIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;manager&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveFor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Collection of all effective permission names</span></span></code></pre></div><p><code>resolveFor()</code> строит результат по приоритету из 3 источников:</p><ol><li>Контекстные выдачи через роли</li><li>Глобальные выдачи через роли</li><li>Переопределения по контексту (<code>forced_on</code> добавляет, <code>forced_off</code> всегда побеждает)</li></ol><p>См. <a href="/clearance-docs/ru/features/contextual-authorization.html">Контекстную авторизацию</a> для концептуального разбора этого приоритета.</p><h2 id="roleservice" tabindex="-1"><code>RoleService</code> <a class="header-anchor" href="#roleservice" aria-label="Permalink to &quot;`RoleService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\RoleService</code> (<code>src/Services/RoleService.php</code>) управляет ceiling-ролями.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\RoleService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole, $parentRole);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">removeParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Метод</th><th>Описание</th></tr></thead><tbody><tr><td><code>setParent($childRole, $parentRole)</code></td><td>Устанавливает ceiling: избыточные разрешения на <code>$childRole</code> сверх набора родителя незаметно обрезаются. Выбрасывает <code>ClearanceScopeViolationException</code>, если дочерняя роль уже является родителем, или родитель уже является дочерней ролью.</td></tr><tr><td><code>removeParent($childRole)</code></td><td>Удаляет связь ceiling.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Ceiling только обрезает - но никогда не выдаёт. Разрешительная родительская роль сама по себе не даёт дочерней роли никаких разрешений. Удаление разрешения у родительской роли автоматически каскадно распространяется на каждую дочернюю роль.</p></div><p>См. <a href="/clearance-docs/ru/features/roles.html">Роли</a> для более глубокого разбора понятия ceiling-роли.</p><h2 id="permissionservice" tabindex="-1"><code>PermissionService</code> <a class="header-anchor" href="#permissionservice" aria-label="Permalink to &quot;`PermissionService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\PermissionService</code> (<code>src/Services/PermissionService.php</code>) обеспечивает CRUD панели Разрешений.</p><p>Он применяет соглашение об именовании <code>group-action</code>, контролируемое ключами конфигурации <code>enforce_naming_convention</code> и <code>naming_separator</code>, и защищает пространство имён разрешений <code>clearance-*</code> от создания, переименования или удаления вне процесса установки.</p><h2 id="guardservice" tabindex="-1"><code>GuardService</code> <a class="header-anchor" href="#guardservice" aria-label="Permalink to &quot;`GuardService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\GuardService</code> (<code>src/Services/GuardService.php</code>) обеспечивает CRUD панели Guards.</p><p>Он внедряет guard&#39;ы, хранящиеся в БД, в <code>auth.guards</code> при загрузке, отфильтрованные по ключу конфигурации <code>allowed_guard_drivers</code> - драйвер вне списка пропускается с предупреждением в лог, а не приводит к повреждению конфигурации аутентификации.</p><h2 id="metaservice" tabindex="-1"><code>MetaService</code> <a class="header-anchor" href="#metaservice" aria-label="Permalink to &quot;`MetaService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\MetaService</code> (<code>src/Services/MetaService.php</code>) читает и записывает <code>clr_meta</code> (отображаемое имя, описание, санитизированную SVG-иконку, цвет) для субъекта-роли или guard&#39;а. Он обеспечивает работу редактора метаданных отображения в панели Настроек.</p><p>SVG-иконки проходят через <code>Rivalex\\Clearance\\Support\\SvgSanitizer</code> (санитайзер на основе allow-list) как перед сохранением, так и при рендеринге.</p><h2 id="userclearanceservice" tabindex="-1"><code>UserClearanceService</code> <a class="header-anchor" href="#userclearanceservice" aria-label="Permalink to &quot;`UserClearanceService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\UserClearanceService</code> (<code>src/Services/UserClearanceService.php</code>) обеспечивает работу панели модуля пользователей:</p><ul><li>Глобальное назначение роли</li><li>Контекстное назначение роли (через <code>UserRoleContext</code>)</li><li>Переопределения разрешений по контексту (через <code>UserContextPermissionOverride</code>, <code>forced_on</code> / <code>forced_off</code>)</li><li>Удаление назначений, каскадно удаляющее переопределения</li></ul><p>Он применяет ограничение по привилегиям: актор, не являющийся <code>super_admin</code>, не может изменять собственные назначения и не может выдать разрешение, которым не обладает сам. См. <a href="/clearance-docs/ru/features/super-admin.html">Super Admin</a> и <a href="/clearance-docs/ru/features/users.html">Пользователи</a>.</p><h2 id="исключения" tabindex="-1">Исключения <a class="header-anchor" href="#исключения" aria-label="Permalink to &quot;Исключения&quot;">​</a></h2><p>Все находятся в <code>src/Exceptions/</code>:</p><table tabindex="0"><thead><tr><th>Исключение</th><th>Выбрасывается когда</th></tr></thead><tbody><tr><td><code>ClearanceConfigException</code></td><td>Читается некорректное или неправильно настроенное значение <code>config/clearance.php</code> (напр. неверный <code>naming_separator</code>).</td></tr><tr><td><code>ClearanceNamingException</code></td><td>Имя разрешения нарушает соглашение об именовании <code>group-action</code> при включённом принудительном соблюдении.</td></tr><tr><td><code>ClearanceProtectedResourceException</code></td><td>Предпринимается попытка изменить защищённое разрешение <code>clearance-*</code> или заблокированный ресурс вне процесса установки.</td></tr><tr><td><code>ClearanceScopeViolationException</code></td><td>Некорректная связь ceiling-роли (родитель пытается стать дочерней ролью или наоборот) или несовпадение области.</td></tr></tbody></table><h2 id="смотрите-также" tabindex="-1">Смотрите также <a class="header-anchor" href="#смотрите-также" aria-label="Permalink to &quot;Смотрите также&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/api/facade.html">Фасад</a> - обёртка в виде статических вызовов вокруг <code>ContextService</code>.</li><li><a href="/clearance-docs/ru/api/traits-directives.html">Трейты и директивы</a> - эквиваленты в виде методов экземпляра и директив Blade.</li><li><a href="/clearance-docs/ru/api/artisan-commands.html">Команды Artisan</a> - <code>clearance:install</code> и <code>clearance:backfill</code>, которые формируют (seed) данные, с которыми работают эти сервисы.</li></ul>',32)])])}const v=a(c,[["render",t]]);export{k as __pageData,v as default};
